class FreqStack:

    def __init__(self):
        self.freq = {}
        self.group = {}

    def push(self, val: int) -> None:
        count = self.freq.get(val, 0)
        self.freq[val] = count + 1
        self.group.setdefault(count + 1, []).append(val)

    def pop(self) -> int:
        max_count = max(self.group.keys())
        val = self.group[max_count].pop()
        self.freq[val] -= 1
        if not self.group[max_count]:
            del self.group[max_count]
        return val
